import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String encodedUserInput = encodeForHtml(userInput); // Encode user input

        PrintWriter out = response.getWriter();
        out.println("<html><body>");
        out.println("<h1>" + encodedUserInput + "</h1>"); // Output properly encoded user input
        out.println("</body></html>");
    }

    private String encodeForHtml(String input) {
        // Implement proper encoding for HTML content to prevent XSS attacks
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#x27;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
